package me.kright.gametools.pga3d

import org.scalatest.funsuite.AnyFunSuiteLike
import org.scalatestplus.scalacheck.ScalaCheckPropertyChecks

/**
 * Pga3dQuaternion is a backward-compatible alias for Pga3dRotor (see Pga3dQuaternion.scala,
 * which is generated by pga3dCodeGen). This test exercises the alias itself: construction,
 * companion factories, and interop with the canonical Pga3dRotor type.
 */
class Pga3dQuaternionAliasTest extends AnyFunSuiteLike with ScalaCheckPropertyChecks:
  test("alias apply construction equals canonical construction") {
    val viaAlias = Pga3dQuaternion(1.0, 2.0, 3.0, 4.0)
    val viaCanonical = Pga3dRotor(1.0, 2.0, 3.0, 4.0)
    assert(viaAlias == viaCanonical)
  }

  test("alias companion factory equals canonical companion factory") {
    val from = Pga3dVector(1, 0, 0)
    val to = Pga3dVector(0, 1, 0)

    val viaAlias: Pga3dQuaternion = Pga3dQuaternion.rotation(from, to)
    val viaCanonical: Pga3dRotor = Pga3dRotor.rotation(from, to)
    assert(viaAlias == viaCanonical)
  }

  test("value typed as the alias can be used in an operation and matches the canonical type") {
    val q: Pga3dQuaternion = Pga3dQuaternion.rotation(Pga3dVector(1, 0, 0), Pga3dVector(0, 1, 0))
    val v = Pga3dVector(1, 0, 0)

    val sandwichedViaAlias = q.sandwich(v)
    val sandwichedViaCanonical = (q: Pga3dRotor).sandwich(v)

    assert(sandwichedViaAlias == sandwichedViaCanonical)
    assert((sandwichedViaAlias - Pga3dVector(0, 1, 0)).norm < 1e-15)
  }
